ROUTEX_PACKAGE_BASE64
elif command -v openssl >/dev/null 2>&1; then
  openssl base64 -d -A -out "$ARCHIVE" <<'ROUTEX_PACKAGE_BASE64'

ROUTEX_PACKAGE_BASE64
else
  die "系统缺少 base64 或 openssl，无法释放安装包。"
fi

if command -v sha256sum >/dev/null 2>&1; then
  ACTUAL_SHA256="$(sha256sum "$ARCHIVE" | awk '{print $1}')"
elif command -v shasum >/dev/null 2>&1; then
  ACTUAL_SHA256="$(shasum -a 256 "$ARCHIVE" | awk '{print $1}')"
else
  die "系统缺少 sha256sum/shasum，无法校验安装包。"
fi
[[ "$ACTUAL_SHA256" == "$PACKAGE_SHA256" ]] || die "安装包校验失败。"

mkdir -p "$WORK_DIR/package"
tar -xzf "$ARCHIVE" -C "$WORK_DIR/package"
INSTALL_SCRIPT="$WORK_DIR/package/RouteX-3xui-v2.9.4/install.sh"
[[ -f "$INSTALL_SCRIPT" ]] || die "安装包结构异常：找不到 install.sh。"

if [[ "${ROUTEX_TEST_ONLY:-0}" == "1" ]]; then
  log "单文件安装器校验通过：$PACKAGE_SHA256"
  exit 0
fi

log "启动 RouteX 安装程序"
chmod +x "$INSTALL_SCRIPT"
bash "$INSTALL_SCRIPT"
